script.text:

function active$Form$(f) {
  var g = f.grid;
  f.setItemValues('keys, ngay_tu, ngay_den, ngay_vao_tu, ngay_vao_den, ma_nv, ma_bp, vi_tri, ma_bac, official_yn', [g._$k, g._dateFrom, g._dateTo, g._dateHireFrom, g._dateHireTo, g._staff, g._dept, g._pos, g._grade, g._official]);
  setObjectFormHidden(f, 'ngay_hl', !(g._official == '1'));
}
function onChange$Form$Object(o) {window.setTimeout(String.format('valid$Form$Authorization(null,\'{0}\');', o.parentForm._id), 2);}
function onChange$Form$Contract(o) {window.setTimeout(String.format('valid$Form$Authorization(null,\'{0}\');', o.parentForm._id), 2);}
function valid$Form$Authorization(f, id) {
  if (f == null) f = $find(id);
  if (f == null) return;
  var o = f.getItem('uy_quyen_yn'), u = $get(String.format('{0}_updateDlgOk', f.get_id())), v = (f.getItemValue('doi_tuong') == 1 && f.getItemValue('hop_dong_yn') == 1);  
	if (v) {
    o.disabled = false;
    if (u.live) o.focus();
  }
  else {
    o.value = 0;
    o.disabled = true;
    if (o.live) u.focus();
  }
}
function refresh$Form$(f) {
  var g = f.grid;
  g._$k = [];
  g.goToPage(-1);
}
function setObjectFormHidden(f, c, b) {
  var o = f.getItem(c);
  o.field.AllowNulls = !b;
  if (b) {
    var grandNode = o.parentNode.parentNode;
    Sys.UI.DomElement.addCssClass(grandNode, 'Required');
    Sys.UI.DomElement.addCssClass(grandNode, f._id);
  }
  if (b) {if (!f._controlFocus) f._controlFocus = o;}
  else $common.setVisible(o.parentNode.parentNode.parentNode, false);
}
